// Prepara un row de historial. El cliente envía:
// {
//   ficha_id | solicitud_id,
//   usuario: { id, nombre, rol } | null (null = cliente o sistema),
//   accion: 'create'|'update'|'delete'|'estado_change'|'adjunto_add'|
//           'adjunto_remove'|'sepa_firmado'|'cliente_respondio'|
//           'a3_grabado'|'a3_desmarcado'|'proyecto_creado'|'enviado_cliente'|
//           'password_reset'|'permiso_change'|'otro',
//   descripcion,
//   cambios: { campo: {before, after} },
//   metadata: { ... }
// }
const ACCIONES_VALIDAS = new Set([
  'create','update','delete','estado_change',
  'adjunto_add','adjunto_remove','sepa_firmado',
  'cliente_respondio','a3_grabado','a3_desmarcado',
  'proyecto_creado','enviado_cliente','password_reset',
  'permiso_change','otro'
]);
const body = ($input.first().json.body) || {};
if (!body.ficha_id && !body.solicitud_id) {
  throw new Error('ficha_id o solicitud_id es obligatorio');
}
const accion = String(body.accion || '').toLowerCase();
if (!ACCIONES_VALIDAS.has(accion)) {
  throw new Error('accion inválida: ' + body.accion);
}
const u = body.usuario || {};
const rolValidado = ['admin','user','cliente','sistema'].includes(u.rol) ? u.rol : 'sistema';
const row = {
  ficha_id:       body.ficha_id || null,
  solicitud_id:   body.solicitud_id || null,
  usuario_id:     u.id || null,
  usuario_nombre: (u.nombre || u.username || '').slice(0, 120) || null,
  usuario_rol:    rolValidado,
  accion:         accion,
  descripcion:    body.descripcion ? String(body.descripcion).slice(0, 500) : null,
  cambios:        JSON.stringify(body.cambios || {}),
  metadata:       JSON.stringify(body.metadata || {})
};
return [{ json: row }];

// Respuesta consistente sin exponer datos internos
const input = $input.all();
let id = null;
const errores = [];
for (const it of input) {
  const j = (it && it.json) ? it.json : it;
  if (!j) continue;
  if (j.error) { errores.push(String(j.error.message || j.error.code || j.error)); continue; }
  if (j.id) { id = j.id; }
}
return [{ json: { success: !!id, id, errores } }];

// Saneo de query params:
// - fichaId (o solicitudId): filtra por una ficha concreta
// - limit: paginación (default 100, max 500)
// - offset
const q = ($input.first().json && $input.first().json.query) || {};
const fichaId = String(q.fichaId || q.ficha_id || '').trim();
const solicitudId = String(q.solicitudId || q.solicitud_id || '').trim();
if (!fichaId && !solicitudId) {
  throw new Error('Se requiere fichaId o solicitudId en query');
}
const limit = Math.min(Math.max(parseInt(q.limit, 10) || 100, 1), 500);
const offset = Math.max(parseInt(q.offset, 10) || 0, 0);
return [{ json: { fichaId, solicitudId, limit, offset } }];

// Devuelve el historial parseando los JSONB como objetos.
function parseJson(v, fb){if(v==null)return fb;if(Array.isArray(v)||typeof v==='object')return v;if(typeof v==='string'){try{return JSON.parse(v);}catch(_){return fb;}}return fb;}
const { limit, offset } = $('Preparar GET Historial').first().json;
const rows = $input.all().map(i => i.json).filter(r => r && r.id);
for (const r of rows) {
  r.cambios  = parseJson(r.cambios, {});
  r.metadata = parseJson(r.metadata, {});
}
return [{ json: {
  historial: rows,
  paging: { limit, offset, count: rows.length, has_more: rows.length >= limit }
} }];
